const fonts = [
        'https://fonts.googleapis.com/css2?family=Source+Code+Pro&display=swap',
        'https://fonts.googleapis.com/css2?family=Roboto&display=swap'
    ];

const doc = document.querySelector('iframe');
const ifrDoc = doc.contentDocument;

const linkEl1 = ifrDoc.createElement("link");
linkEl1.href = "https://fonts.googleapis.com";
linkEl1.rel = "preconnect";
linkEl1.crossorigin = true;
ifrDoc.head.appendChild(linkEl1);

var linkEl2 = ifrDoc.createElement("link");
linkEl2.href = "https://fonts.gstatic.com";
linkEl2.rel = "preconnect";
ifrDoc.head.appendChild(linkEl2);

fonts.forEach(font => {
    var linkEl3 = ifrDoc.createElement("link");
    linkEl3.href = font;
    linkEl3.rel = "stylesheet";
    ifrDoc.head.appendChild(linkEl3);
});
